#include <stdio.h>
#include <stdlib.h>
#define MAXA 1000000
int spf[MAXA+1];
void sieve(){
    for(int i=2;i<=MAXA;i++) spf[i]=0;
    for(int i=2;i<=MAXA;i++) if(!spf[i]){
        spf[i]=i;
        if((long long)i*i<=MAXA) for(long long j=(long long)i*i;j<=MAXA;j+=i) if(!spf[j]) spf[j]=i;
    }
}
int main(){
    sieve();
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        // map prime -> max exponent (simple array because prime <= MAXA)
        static int maxExp[MAXA+1];
        // reset only used entries later
        static int used[MAXA+1];
        int usedCnt=0;
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            while(x>1){
                int p=spf[x];
                int cnt=0;
                while(x%p==0){x/=p;cnt++;}
                if(!used[p]){used[p]=1; usedCnt++; maxExp[p]=cnt;}
                else if(cnt>maxExp[p]) maxExp[p]=cnt;
            }
        }
        long long ans=0;
        for(int i=2;i<=MAXA;i++) if(used[i]){ans+=maxExp[i]; used[i]=0;}
        printf("%lld\n",ans);
    }
    return 0;
}

