#include <bits/stdc++.h>
using namespace std;
const int MAXA = 1000000;
int spf[MAXA+1];
void sieve(){
    for(int i=2;i<=MAXA;i++) if(!spf[i]){
        spf[i]=i;
        if(1LL*i*i<=MAXA) for(long long j=1LL*i*i;j<=MAXA;j+=i) if(!spf[j]) spf[j]=i;
    }
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    sieve();
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_map<int,int> best; // prime -> max exponent
        for(int i=0;i<N;i++){
            int x; cin>>x;
            while(x>1){
                int p=spf[x];
                int cnt=0;
                while(x%p==0){x/=p;cnt++;}
                auto it=best.find(p);
                if(it==best.end()||cnt>it->second) best[p]=cnt;
            }
        }
        long long ans=0;
        for(auto &kv:best) ans+=kv.second;
        cout<<ans<<"\n";
    }
    return 0;
}

