import java.io.*;
import java.util.*;
public class Main {
    static final int MAXA = 1_000_000;
    static int[] spf = new int[MAXA + 1];
    static void sieve(){
        for(int i=2;i<=MAXA;i++) if(spf[i]==0){
            spf[i]=i;
            if((long)i*i<=MAXA) for(long j=(long)i*i;j<=MAXA;j+=i) if(spf[(int)j]==0) spf[(int)j]=i;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        sieve();
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            HashMap<Integer,Integer> best = new HashMap<>();
            for(int i=0;i<N;i++){
                int x = fs.nextInt();
                while(x>1){
                    int p = spf[x];
                    int cnt = 0;
                    while(x%p==0){x/=p;cnt++;}
                    best.merge(p, cnt, Math::max);
                }
            }
            long ans = 0;
            for(int v: best.values()) ans += v;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if(ptr >= len){ len = in.read(buffer); ptr = 0; if(len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while(c <= ' ');
            if(c=='-'){ sign = -1; c = readByte(); }
            while(c > ' '){ val = val*10 + (c - '0'); c = readByte(); }
            return val*sign;
        }
    }
}

