import sys
MAXA = 10**6
spf = [0]*(MAXA+1)
for i in range(2, MAXA+1):
    if spf[i]==0:
        spf[i]=i
        if i*i <= MAXA:
            step = i
            start = i*i
            for j in range(start, MAXA+1, step):
                if spf[j]==0:
                    spf[j]=i

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        best = {}
        for _ in range(N):
            x = int(next(it))
            while x > 1:
                p = spf[x]
                cnt = 0
                while x % p == 0:
                    x //= p
                    cnt += 1
                if cnt > best.get(p, 0):
                    best[p] = cnt
        ans = sum(best.values())
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

